<template><div class="profile-grid"><section class="profile-card identity"><div class="identity-bg"></div><div class="avatar">{{auth.user?.name?.slice(0,1)||'药'}}</div><h2>{{auth.user?.name||'药房人员'}}</h2><p>@{{auth.user?.username}}</p><el-tag type="success" round>药房工作站</el-tag><div class="identity-info"><div><span>联系电话</span><strong>{{auth.user?.phone||'暂未登记'}}</strong></div><div><span>账号状态</span><strong class="active-dot">正常使用</strong></div><div><span>加入时间</span><strong>{{formatDate(auth.user?.createTime)}}</strong></div></div></section><section class="profile-card security"><span class="eyebrow">ACCOUNT SECURITY</span><h1>账号与安全</h1><p>定期修改密码，保护处方与患者数据安全。</p><div class="security-banner"><el-icon><Lock/></el-icon><div><strong>登录密码</strong><span>密码采用 BCrypt 加密保存</span></div><el-button type="primary" plain @click="dialog=true">修改密码</el-button></div><div class="security-notes"><h3>安全建议</h3><p><el-icon><CircleCheck/></el-icon>密码长度不少于 6 位，建议包含字母与数字</p><p><el-icon><CircleCheck/></el-icon>离开工作站时请及时退出登录</p><p><el-icon><CircleCheck/></el-icon>不得与其他工作人员共用账号</p></div></section><el-dialog v-model="dialog" title="修改登录密码" width="440px"><el-form ref="formRef" :model="form" :rules="rules" label-position="top"><el-form-item label="当前密码" prop="oldPassword"><el-input v-model="form.oldPassword" type="password" show-password/></el-form-item><el-form-item label="新密码" prop="newPassword"><el-input v-model="form.newPassword" type="password" show-password/></el-form-item><el-form-item label="确认新密码" prop="confirm"><el-input v-model="form.confirm" type="password" show-password/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" :loading="saving" @click="submit">确认修改</el-button></template></el-dialog></div></template>
<script setup lang="ts">import{reactive,ref}from'vue';import{ElMessage,type FormInstance,type FormRules}from'element-plus';import{Lock,CircleCheck}from'@element-plus/icons-vue';import{changePassword}from'@/api/pharmacy';import{useAuthStore}from'@/stores/auth';const auth=useAuthStore(),dialog=ref(false),saving=ref(false),formRef=ref<FormInstance>(),form=reactive({oldPassword:'',newPassword:'',confirm:''});const validateConfirm=(_:unknown,value:string,cb:(e?:Error)=>void)=>value!==form.newPassword?cb(new Error('两次输入的新密码不一致')):cb();const rules:FormRules={oldPassword:[{required:true,message:'请输入当前密码',trigger:'blur'}],newPassword:[{required:true,message:'请输入新密码',trigger:'blur'},{min:6,message:'新密码至少6位',trigger:'blur'}],confirm:[{required:true,message:'请再次输入新密码',trigger:'blur'},{validator:validateConfirm,trigger:'blur'}]};const formatDate=(s?:string)=>s?new Date(s).toLocaleDateString('zh-CN'):'--';const submit=async()=>{if(!await formRef.value?.validate().catch(()=>false))return;saving.value=true;try{await changePassword(form.oldPassword,form.newPassword);ElMessage.success('密码修改成功');dialog.value=false;Object.assign(form,{oldPassword:'',newPassword:'',confirm:''})}finally{saving.value=false}}</script>
